#include<bits/stdc++.h>
using namespace std;
const int N = 5e5+5;
int T,n,m,l,r,ans;
long long k,a[N],tmp[N],c[N],h;
bool check(int L,int R,int nxt){
    for(int i=R+1;i<=nxt;i++)tmp[i]=a[i];
    sort(tmp+R+1,tmp+nxt+1);
    int p1=L,p2=R+1,cnt=L-1;
    while(p1<=R&&p2<=nxt){
        if(a[p1]<tmp[p2])c[++cnt]=a[p1++];
        else c[++cnt]=tmp[p2++];
    }
    while(p1<=R)c[++cnt]=a[p1++];
    while(p2<=nxt)c[++cnt]=tmp[p2++];
    long long sum=0;
    for(int i=1,x=L,y=nxt;i<=m&&x<y;i++,x++,y--){
        sum+=(c[y]-c[x])*(c[y]-c[x]);
        if(sum>k)return 0;
    }
    return 1;
}
int main(){
    cin>>T;
    while(T--){
        memset(a,0,sizeof(a));
        memset(c,0,sizeof(c));
        memset(tmp,0,sizeof(tmp));
        cin>>n>>m>>k;
        for(int i=1;i<=n;i++)cin>>a[i];
        l=1,r=1,h=1,ans=0;
        while(r<=n){
            h=1;
            while(h>0){
                if(r+h<=n&&check(l,r,r+h)){
                    r+=h;h<<=1;
                    for(int i=l;i<=r;i++)a[i]=c[i];
                }
                else h>>=1;
            }
            ans++;l=r+1;r=l,h=1;
        }
        cout<<ans<<"\n";
    }
    return 0;
}
